def dijkstra(graph: dict, start: str) -> dict:
    """
    Implement Dijkstra's shortest path algorithm using Claude AI.

    Args:
        graph: dict mapping node -> list of (neighbour, weight) tuples
        start: starting node

    Returns:
        dict of shortest distances from start
    """
    client = anthropic.Anthropic()

    # Create a prompt for Claude to implement Dijkstra's algorithm
    prompt = f"""
    I need you to run Dijkstra's shortest path algorithm on the following graph and return the result as JSON.

    Graph (adjacency list format where each node maps to list of [neighbour, weight] pairs):
    {json.dumps(graph)}

    Starting node: {start}

    Please implement and execute Dijkstra's algorithm step by step:
    1. Initialize distances dict with start=0, all others=infinity
    2. Use a priority queue (min-heap) to process nodes
    3. For each node, update distances to neighbors if shorter path found
    4. Return the final distances dict

    Return ONLY a JSON object with the shortest distances from the start node to all reachable nodes.
    Format: {{"node1": distance1, "node2": distance2, ...}}
    Include only reachable nodes (where distance < infinity).
    Do not include any explanation, only the JSON object.
    """

    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[
            {"role": "user", "content": prompt}
        ]
    )

    # Parse the response
    response_text = message.content[0].text.strip()

    # Extract JSON from the response
    try:
        # Try to parse the response directly as JSON
        distances = json.loads(response_text)
        # Convert all values to numbers
        return {str(k): float(v) if v != float('inf') else float('inf') 
                for k, v in distances.items()}
    except json.JSONDecodeError:
        # If direct parsing fails, try to extract JSON from the response
        import re
        json_match = re.search(r'\{[^{}]*\}', response_text, re.DOTALL)
        if json_match:
            distances = json.loads(json_match.group())
            return {str(k): float(v) if v != float('inf') else float('inf') 
                    for k, v in distances.items()}
        else:
            # Fall back to local implementation if AI response parsing fails
            return _local_dijkstra(graph, start)


