def execute_python_snippet(code: str) -> dict:
    """
    Executes the given Python code string and returns a dict of the local variables defined by it.
    Uses Claude AI with tool use to analyze and execute the code.

    Args:
        code: Python code string to execute

    Returns:
        Dictionary of local variables defined by the code
    """
    client = anthropic.Anthropic()

    tools = [
        {
            "name": "execute_code",
            "description": "Execute Python code and return the local variables",
            "input_schema": {
                "type": "object",
                "properties": {
                    "code": {
                        "type": "string",
                        "description": "The Python code to execute"
                    }
                },
                "required": ["code"]
            }
        }
    ]

    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        tools=tools,
        messages=[
            {
                "role": "user",
                "content": f"Please execute this Python code and tell me what local variables it defines: {code}"
            }
        ]
    )

    if message.stop_reason == "tool_use":
        for content_block in message.content:
            if content_block.type == "tool_use" and content_block.name == "execute_code":
                local_vars = {}
                exec(code, {}, local_vars)

                tool_result_message = {
                    "role": "user",
                    "content": [
                        {
                            "type": "tool_result",
                            "tool_use_id": content_block.id,
                            "content": json.dumps({"variables": str(local_vars)})
                        }
                    ]
                }

                final_message = client.messages.create(
                    model="claude-opus-4-5",
                    max_tokens=1024,
                    tools=tools,
                    messages=[
                        {
                            "role": "user",
                            "content": f"Please execute this Python code and tell me what local variables it defines: {code}"
                        },
                        {
                            "role": "assistant",
                            "content": message.content
                        },
                        tool_result_message
                    ]
                )

                return local_vars

    local_vars = {}
    exec(code, {}, local_vars)
    return local_vars


def main():
    test_cases = [
        "x = 1 + 1",
        "a = 5\nb = 10\nc = a + b",
        "name = 'Hello'\ngreeting = name + ' World'",
        "numbers = [1, 2, 3, 4, 5]\ntotal = sum(numbers)\naverage = total / len(numbers)"
    ]

    for code in test_cases:
        print(f"\nExecuting code: {repr(code)}")
        result = execute_python_snippet(code)
        print(f"Result: {result}")


if __name__ == "__main__":
    main()

