import anthropic
import subprocess


def run_shell_command(cmd: str) -> str:
    """
    Execute a shell command and return its standard output as a stripped string.
    """
    result = subprocess.run(
        cmd,
        shell=True,
        capture_output=True,
        text=True
    )
    return result.stdout.strip()


def main():
    client = anthropic.Anthropic()

    # Define the shell command tool
    tools = [
        {
            "name": "run_shell_command",
            "description": "Execute a shell command and return its standard output",
            "input_schema": {
                "type": "object",
                "properties": {
                    "cmd": {
                        "type": "string",
                        "description": "The shell command to execute"
                    }
                },
                "required": ["cmd"]
            }
        }
    ]

    # Example: Ask Claude to use the shell command tool
    messages = [
        {
            "role": "user",
            "content": "Please run the command 'echo Hello, World!' and tell me what it outputs."
        }
    ]

    print("Sending request to Claude...")

    # Agentic loop
    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            tools=tools,
            messages=messages
        )

        print(f"Stop reason: {response.stop_reason}")

        # Check if we should stop
        if response.stop_reason == "end_turn":
            # Extract and print the final response
            for block in response.content:
                if hasattr(block, 'text'):
                    print(f"\nClaude's response: {block.text}")
            break

        # Process tool calls if any
        if response.stop_reason == "tool_use":
            # Add assistant's response to messages
            messages.append({
                "role": "assistant",
                "content": response.content
            })

            # Process each tool use block
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    print(f"\nClaude wants to run command: {block.input['cmd']}")

                    # Execute the command
                    output = run_shell_command(block.input['cmd'])
                    print(f"Command output: {output}")

                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": output
                    })

            # Add tool results to messages
            messages.append({
                "role": "user",
                "content": tool_results
            })
        else:
            # No more tool calls, we're done
            for block in response.content:
                if hasattr(block, 'text'):
                    print(f"\nClaude's response: {block.text}")
            break

    # Demonstrate direct usage of run_shell_command
    print("\n--- Direct Function Usage ---")
    test_commands = [
        "echo 'Testing run_shell_command'",
        "pwd",
        "date",
        "echo '  spaces around  '"
    ]

    for cmd in test_commands:
        output = run_shell_command(cmd)
        print(f"Command: {cmd}")
        print(f"Output: '{output}'")
        print()


if __name__ == "__main__":
    main()

