def execute_command_with_claude(user_request: str) -> str:
    """Use Claude to determine and execute the appropriate shell command."""
    client = anthropic.Anthropic()

    tools = [
        {
            "name": "run_shell_command",
            "description": "Execute a shell command and return its stdout. Use this to run system commands.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "cmd": {
                        "type": "string",
                        "description": "The shell command to execute"
                    }
                },
                "required": ["cmd"]
            }
        }
    ]

    messages = [
        {
            "role": "user",
            "content": user_request
        }
    ]

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        tools=tools,
        messages=messages
    )

    while response.stop_reason == "tool_use":
        tool_use_block = None
        for block in response.content:
            if block.type == "tool_use":
                tool_use_block = block
                break

        if tool_use_block:
            command = tool_use_block.input["cmd"]
            command_output = run_shell_command(command)

            messages.append({
                "role": "assistant",
                "content": response.content
            })

            messages.append({
                "role": "user",
                "content": [
                    {
                        "type": "tool_result",
                        "tool_use_id": tool_use_block.id,
                        "content": command_output
                    }
