def load_yaml_config(filepath: str) -> dict:
    """
    Reads a YAML file from the given path and returns its contents as a Python dictionary.
    Uses Claude AI with tool use to implement the file reading functionality.

    Args:
        filepath: Path to the YAML file

    Returns:
        Dictionary containing the YAML file contents
    """
    client = anthropic.Anthropic()

    tools = [
        {
            "name": "read_yaml_file",
            "description": "Reads a YAML file from the filesystem and returns its contents",
            "input_schema": {
                "type": "object",
                "properties": {
                    "filepath": {
                        "type": "string",
                        "description": "The path to the YAML file to read"
                    }
                },
                "required": ["filepath"]
            }
        }
    ]

    messages = [
        {
            "role": "user",
            "content": f"Please read the YAML file at path '{filepath}' and return its contents as a dictionary. Use the read_yaml_file tool to do this."
        }
    ]

    yaml_result = None

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=tools,
            messages=messages
        )

        if response.stop_reason == "tool_use":
            tool_use_block = None
            for block in response.content:
                if block.type == "tool_use":
                    tool_use_block = block
                    break

            if tool_use_block and tool_use_block.name == "read_yaml_file":
                tool_filepath = tool_use_block.input.get("filepath", filepath)

                try:
                    with open(tool_filepath, 'r') as f:
                        yaml_content = yaml.safe_load(f)

                    if yaml_content is None:
                        yaml_content = {}

                    tool_result = {
                        "success": True,
                        "content": yaml_content,
                        "message": f"Successfully read YAML file from {tool_filepath}"
                    }
                    yaml_result = yaml_content

                except FileNotFoundError:
                    tool_result = {
                        "success": False,
                        "error": f"File not found: {tool_filepath}"
                    }
                except yaml.YAMLError as e:
                    tool_result = {
                        "success": False,
                        "error": f"YAML parsing error: {str(e)}"
                    }
                except Exception as e:
                    tool_result = {
                        "success": False,
                        "error": f"Unexpected error: {str(e)}"
                    }

                messages.append({
                    "role": "assistant",
                    "content": response.content
                })

                messages.append({
                    "role": "user",
                    "content": [
                        {
                            "type": "tool_result",
                            "tool_use_id": tool_use_block.id,
                            "content": json.dumps(tool_result)
                        }
                    ]
                })

                if not tool_result["success"]:
                    raise Exception(tool_result["error"])

        elif response.stop_reason == "end_turn":
            break
        else:
            break

    if yaml_result is not None:
        return yaml_result

    raise Exception(f"Failed to load YAML file: {filepath}")


