                    }
                },
                "required": ["module_name", "import_successful"]
            }
        }
    ]

    messages = [
        {
            "role": "user",
            "content": f"Please help me import the Python module '{module_name}'. Use the import_python_module tool to indicate whether this module can be imported."
        }
